import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.DYQ4mM3C.js";const h=JSON.parse('{"title":"Recovery","description":"","frontmatter":{},"headers":[],"relativePath":"recovery.md","filePath":"recovery.md","lastUpdated":1783306671000}'),i={name:"recovery.md"};function l(s,e,n,c,d,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="recovery" tabindex="-1">Recovery <a class="header-anchor" href="#recovery" aria-label="Permalink to &quot;Recovery&quot;">​</a></h1><p>This guide covers local recovery for EnvVault.</p><h2 id="os-credential-store-unavailable" tabindex="-1">OS Credential Store Unavailable <a class="header-anchor" href="#os-credential-store-unavailable" aria-label="Permalink to &quot;OS Credential Store Unavailable&quot;">​</a></h2><p>Symptoms:</p><ul><li><code>ENVVAULT_KEYRING_UNAVAILABLE</code></li><li><code>ENVVAULT_KEYRING_LOCKED</code></li><li>Credential add, credential resolution, or proxy use fails while reading the OS credential store.</li></ul><p>Actions:</p><ol><li>Unlock the platform credential store.</li><li>Re-run <code>envvault doctor</code>.</li><li>Re-add affected credentials if the platform credential store entry is missing.</li><li>Do not store credentials in repository files as a fallback.</li></ol><h2 id="corrupt-or-missing-local-state" tabindex="-1">Corrupt or Missing Local State <a class="header-anchor" href="#corrupt-or-missing-local-state" aria-label="Permalink to &quot;Corrupt or Missing Local State&quot;">​</a></h2><p>Symptoms:</p><ul><li><code>envvault doctor</code> reports config, data, cache, or SQLite integrity errors.</li><li>Optional proxies cannot be loaded.</li></ul><p>Actions:</p><ol><li>Preserve the existing data directory for investigation.</li><li>Restore from the migration backup if available.</li><li>If recovery is not possible, run <code>envvault reset --dry-run</code>, then <code>envvault reset --yes</code>.</li><li>Recreate credentials and optional proxies.</li></ol><h2 id="stale-runtime-lock-or-crash" tabindex="-1">Stale Runtime Lock or Crash <a class="header-anchor" href="#stale-runtime-lock-or-crash" aria-label="Permalink to &quot;Stale Runtime Lock or Crash&quot;">​</a></h2><p>Symptoms:</p><ul><li><code>ENVVAULT_LOCK_TIMEOUT</code></li><li>Doctor reports stale runtime state.</li><li>A previous EnvVault process was killed while starting or stopping local runtime state.</li></ul><p>Actions:</p><ol><li>Confirm no active <code>envvault</code> process is still running for the same user.</li><li>Run <code>envvault doctor</code>.</li><li>Run <code>envvault doctor --repair</code> to remove stale EnvVault runtime locks and temporary files.</li><li>Re-run <code>envvault doctor</code> and investigate any remaining errors before starting another credential operation.</li></ol><h2 id="suspected-secret-exposure" tabindex="-1">Suspected Secret Exposure <a class="header-anchor" href="#suspected-secret-exposure" aria-label="Permalink to &quot;Suspected Secret Exposure&quot;">​</a></h2><p>Actions:</p><ol><li>Stop using affected credentials or proxies.</li><li>Rotate affected credentials in the upstream service.</li><li>Re-add the rotated value to EnvVault.</li><li>Scan config, data, cache, logs, audit files, shell history, and temporary directories for the exposure marker.</li><li>Treat any leaked local proxy token as usable until the child process exits or the token expires.</li></ol><p>EnvVault cannot revoke application-side writes that already happened with a valid credential.</p>',21)])])}const v=t(i,[["render",l]]);export{h as __pageData,v as default};
